class Solution:
    def getMaxFunctionValue(self, receiver, k):
        n = len(receiver)
        steps = k + 1
        LOG = max(1, steps.bit_length())
        up = [[0] * n for _ in range(LOG)]
        sm = [[0] * n for _ in range(LOG)]
        for v in range(n):
            up[0][v] = receiver[v]
            sm[0][v] = v
        for j in range(1, LOG):
            for v in range(n):
                mid = up[j - 1][v]
                up[j][v] = up[j - 1][mid]
                sm[j][v] = sm[j - 1][v] + sm[j - 1][mid]
        best = 0
        for start in range(n):
            cur = start
            total = 0
            rem = steps
            for j in range(LOG - 1, -1, -1):
                if (rem >> j) & 1:
                    total += sm[j][cur]
                    cur = up[j][cur]
            best = max(best, total)
        return best

