var getMaxFunctionValue = function(receiver, k) {
    const n = receiver.length;
    const steps = k + 1;
    let LOG = 1;
    while (Math.pow(2, LOG) <= steps) LOG++;
    LOG += 1;
    const up = Array.from({length: LOG}, () => new Array(n).fill(0));
    const sm = Array.from({length: LOG}, () => new Array(n).fill(0));
    for (let v = 0; v < n; v++) { up[0][v] = receiver[v]; sm[0][v] = v; }
    for (let j = 1; j < LOG; j++) {
        for (let v = 0; v < n; v++) {
            const mid = up[j - 1][v];
            up[j][v] = up[j - 1][mid];
            sm[j][v] = sm[j - 1][v] + sm[j - 1][mid];
        }
    }
    let best = 0;
    for (let start = 0; start < n; start++) {
        let cur = start, total = 0;
        let rem = steps;
        for (let j = LOG - 1; j >= 0; j--) {
            const p2 = Math.pow(2, j);
            if (rem >= p2) {
                total += sm[j][cur];
                cur = up[j][cur];
                rem -= p2;
            }
        }
        if (total > best) best = total;
    }
    return best;
};
